233	            i = i + 1; /* skip closing quote */
234	            tok_end();
235	            token_type[token_count] = TOK_QUOTED;
236	            token_count = token_count + 1;
237	
238	        } else if (line[i] == 123) { /* '{' — brace block */
239	            token_starts[token_count] = token_pool_used;
240	            int depth = 1;
241	            tok_putc(line[i]); /* opening brace */
242	            i = i + 1;
243	            while (line[i] && depth > 0) {
244	                if (line[i] == 123) depth = depth + 1;
245	                if (line[i] == 125) depth = depth - 1;
246	                tok_putc(line[i]);
247	                i = i + 1;
248	            }
249	            if (depth != 0) {
250	                uart_puts("error: unterminated brace");
251	                uart_newline();
252	                return -1;
253	            }
254	            tok_end();
255	            token_type[token_count] = TOK_BLOCK;
256	            token_count = token_count + 1;
257	
258	        } else { /* bare word */
259	            token_starts[token_count] = token_pool_used;
260	            while (line[i] && line[i] != 32 && line[i] != 9
261	                   && line[i] != 35) {
262	                tok_putc(line[i]);
263	                i = i + 1;
264	            }
265	            tok_end();
266	            token_type[token_count] = TOK_WORD;
267	            token_count = token_count + 1;
268	        }
269	    }
270	
271	    return token_count;
272	}
273	
274	/* ---- Value type system ---- */
275	
276	/* Type tags */
277	#define VAL_INT 0
278	#define VAL_STR 1
279	#define VAL_REC 2
280	
281	/* Value storage limits */
282	#define MAX_VALS       64
283	
284	/* Parallel arrays for value storage.
285	 * 2D arrays are flattened to 1D to avoid large strides that
286	 * exceed tc24r/as24's lc immediate range (0..127). */
287	int  val_type[MAX_VALS];
288	int  val_int[MAX_VALS];
289	/* 64 * 128 = 8192 */
290	#define VAL_STR_POOL_SIZE 8192
291	/* 64 * 16 = 1024 */
292	#define VAL_REC_POOL_SIZE 1024
293	
294	char val_str_pool[VAL_STR_POOL_SIZE];          /* flat string pool */
295	int  val_rec_fld[VAL_REC_POOL_SIZE];           /* field name value indices */
296	int  val_rec_val[VAL_REC_POOL_SIZE];           /* field value indices */
297	int  val_rec_count[MAX_VALS];
298	int  val_count;
299	
300	/* Index helpers for flat arrays */
301	int vsp(int idx) { return idx * MAX_VAR_VAL; }  /* val_str_pool offset */
302	int vrf(int idx, int f) { return idx * MAX_FIELDS + f; } /* rec field offset */
303	
304	/* Get pointer to a value's string data */
305	char *val_str_ptr(int idx) {
306	    return val_str_pool + vsp(idx);
307	}
308	
309	/* Reset all values (call at start or between scripts) */
310	void val_reset() {
311	    val_count = 0;
312	}
313	
314	/* Allocate a new integer value. Returns index, or -1 on overflow. */
315	int val_new_int(int n) {
316	    if (val_count >= MAX_VALS) return -1;
317	    int idx = val_count;
318	    val_type[idx] = VAL_INT;
319	    val_int[idx] = n;
320	    val_count = val_count + 1;
321	    return idx;
322	}
323	
324	/* Allocate a new string value. Returns index, or -1 on overflow. */
325	int val_new_str(char *s) {
326	    if (val_count >= MAX_VALS) return -1;
327	    int idx = val_count;
328	    val_type[idx] = VAL_STR;
329	    /* Copy string, truncate if needed */
330	    char *dst = val_str_ptr(idx);
331	    int i = 0;
332	    while (s[i] && i < MAX_VAR_VAL - 1) {
333	        dst[i] = s[i];
334	        i = i + 1;
335	    }
336	    dst[i] = 0;
337	    val_count = val_count + 1;
338	    return idx;
339	}
340	
341	/* Allocate a new empty record. Returns index, or -1 on overflow. */
342	int val_new_rec() {
343	    if (val_count >= MAX_VALS) return -1;
344	    int idx = val_count;
345	    val_type[idx] = VAL_REC;
346	    val_rec_count[idx] = 0;
347	    val_count = val_count + 1;
348	    return idx;
349	}
350	
351	/* Set a field in a record. field_name_idx and val_idx are value indices.
352	 * Returns 0 on success, -1 on error. */
353	int val_rec_set(int rec_idx, int field_name_idx, int val_idx) {
354	    if (rec_idx < 0 || rec_idx >= val_count) return -1;
355	    if (val_type[rec_idx] != VAL_REC) return -1;
356	
357	    /* Check if field already exists — update in place */
358	    int fc = val_rec_count[rec_idx];
359	    int i = 0;
360	    while (i < fc) {
361	        if (val_rec_fld[vrf(rec_idx, i)] == field_name_idx) {
362	            val_rec_val[vrf(rec_idx, i)] = val_idx;
363	            return 0;
364	        }
365	        i = i + 1;
366	    }
367	
368	    /* Add new field */
369	    if (fc >= MAX_FIELDS) return -1;
370	    val_rec_fld[vrf(rec_idx, fc)] = field_name_idx;
371	    val_rec_val[vrf(rec_idx, fc)] = val_idx;
372	    val_rec_count[rec_idx] = fc + 1;
373	    return 0;
374	}
375	
376	/* Get a field value from a record by field name string.
377	 * Returns value index, or -1 if not found. */
378	int val_rec_get(int rec_idx, char *field_name) {
379	    if (rec_idx < 0 || rec_idx >= val_count) return -1;
380	    if (val_type[rec_idx] != VAL_REC) return -1;
381	
382	    int fc = val_rec_count[rec_idx];
383	    int i = 0;
384	    while (i < fc) {
385	        int fn_idx = val_rec_fld[vrf(rec_idx, i)];
386	        if (val_type[fn_idx] == VAL_STR && str_eq(val_str_ptr(fn_idx), field_name)) {
387	            return val_rec_val[vrf(rec_idx, i)];
388	        }
389	        i = i + 1;
390	    }
391	    return -1;
392	}
393	
394	/* Check if a record has a field. Returns 1 if exists, 0 if not. */
395	int val_rec_has(int rec_idx, char *field_name) {
396	    return val_rec_get(rec_idx, field_name) >= 0;
397	}
398	
399	/* Format a value as a string into buf. Returns buf. */
400	char *val_to_str(int idx, char *buf) {
401	    if (idx < 0 || idx >= val_count) {
402	        buf[0] = 0;
403	        return buf;
404	    }
405	    if (val_type[idx] == VAL_INT) {
406	        int_to_str(buf, val_int[idx]);
407	    } else if (val_type[idx] == VAL_STR) {
408	        str_copy(buf, val_str_ptr(idx));
409	    } else if (val_type[idx] == VAL_REC) {
410	        /* Debug representation: {field1: val1, field2: val2} */
411	        int p = 0;
412	        buf[p] = 123; /* '{' */
413	        p = p + 1;
414	        int fc = val_rec_count[idx];
415	        int i = 0;
416	        while (i < fc && p < MAX_VAR_VAL - 10) {
417	            if (i > 0) {
418	                buf[p] = 44; /* ',' */
419	                p = p + 1;
420	                buf[p] = 32; /* ' ' */
421	                p = p + 1;
422	            }
423	            /* field name */
424	            int fn_idx = val_rec_fld[vrf(idx, i)];
425	            char tmp[MAX_VAR_VAL];
426	            val_to_str(fn_idx, tmp);
427	            int k = 0;
428	            while (tmp[k] && p < MAX_VAR_VAL - 5) {
429	                buf[p] = tmp[k];
430	                p = p + 1;
431	                k = k + 1;
432	            }
433	            buf[p] = 58; /* ':' */
434	            p = p + 1;
435	            buf[p] = 32; /* ' ' */
436	            p = p + 1;
437	            /* field value */
438	            int fv_idx = val_rec_val[vrf(idx, i)];
439	            val_to_str(fv_idx, tmp);
440	            k = 0;
441	            while (tmp[k] && p < MAX_VAR_VAL - 3) {
442	                buf[p] = tmp[k];
443	                p = p + 1;
444	                k = k + 1;
445	            }
446	            i = i + 1;
447	        }
448	        buf[p] = 125; /* '}' */
449	        p = p + 1;
450	        buf[p] = 0;
451	    } else {
452	        buf[0] = 0;
453	    }
454	    return buf;
455	}
