457	/* Compare two values for equality. Returns 1 if equal, 0 if not. */
458	int val_eq(int a, int b) {
459	    if (a < 0 || a >= val_count || b < 0 || b >= val_count) return 0;
460	    if (val_type[a] != val_type[b]) return 0;
461	    if (val_type[a] == VAL_INT) {
462	        return val_int[a] == val_int[b];
463	    }
464	    if (val_type[a] == VAL_STR) {
465	        return str_eq(val_str_ptr(a), val_str_ptr(b));
466	    }
467	    /* Records: equal only if same index */
468	    return a == b;
469	}
470	
471	/* Truthiness: nonzero int = true, nonempty string = true,
472	 * record = true, invalid = false. */
473	int val_is_truthy(int idx) {
474	    if (idx < 0 || idx >= val_count) return 0;
475	    if (val_type[idx] == VAL_INT) {
476	        return val_int[idx] != 0;
477	    }
478	    if (val_type[idx] == VAL_STR) {
479	        char *sp = val_str_ptr(idx);
480	        return sp[0] != 0;
481	    }
482	    /* Records are always truthy */
483	    return 1;
484	}
