487	
488	/* Flat name pool: var i's name starts at var_name_pool[i * MAX_VAR_NAME] */
489	#define VAR_NAME_POOL_SIZE 2048  /* 64 * 32 = 2048 */
490	char var_name_pool[VAR_NAME_POOL_SIZE];
491	int  var_val[MAX_VARS];   /* value index into value storage */
492	int  var_count;
