499	/* Find variable index by name. Returns -1 if not found. */
500	int env_find(char *name) {
501	    int i = 0;
502	    while (i < var_count) {
503	        if (str_eq(var_name(i), name)) return i;
504	        i = i + 1;
505	    }
506	    return -1;
507	}
