509	/* Set or update a variable. Returns 0 on success, -1 on overflow. */
510	int env_set(char *name, int val_idx) {
511	    int i = env_find(name);
512	    if (i >= 0) {
513	        var_val[i] = val_idx;
514	        return 0;
515	    }
516	    if (var_count >= MAX_VARS) return -1;
517	    /* Copy name into pool */
518	    char *dst = var_name(var_count);
519	    int k = 0;
520	    while (name[k] && k < MAX_VAR_NAME - 1) {
521	        dst[k] = name[k];
522	        k = k + 1;
523	    }
524	    dst[k] = 0;
525	    var_val[var_count] = val_idx;
526	    var_count = var_count + 1;
527	    return 0;
528	}
