542	/* Remove a variable. Returns 0 on success, -1 if not found. */
543	int env_unset(char *name) {
544	    int i = env_find(name);
545	    if (i < 0) return -1;
546	    /* Shift remaining vars down */
547	    while (i < var_count - 1) {
548	        str_copy(var_name(i), var_name(i + 1));
549	        var_val[i] = var_val[i + 1];
550	        i = i + 1;
551	    }
552	    var_count = var_count - 1;
553	    return 0;
554	}
