561	/* ---- Variable substitution ---- */
562	
563	/* Expanded token buffer — tokens after $var substitution */
564	#define EXPAND_POOL_SIZE 2048
565	char expand_pool[EXPAND_POOL_SIZE];
566	int  expand_starts[MAX_TOKENS];
567	int  expand_count;
568	int  expand_pool_used;
569	
570	/* Parse a variable reference from a token string starting at $.
571	 * Writes var name into vname, field name into fname (or empty).
572	 * Returns number of chars consumed (not counting the $). */
573	int parse_var_ref(char *s, char *vname, char *fname) {
574	    int i = 0;
575	    int vi = 0;
576	    /* Read variable name: alphanumeric and underscore */
577	    while (s[i] && s[i] != 46 /* '.' */ && s[i] != 32 && s[i] != 9
578	           && vi < MAX_VAR_NAME - 1) {
579	        vname[vi] = s[i];
580	        vi = vi + 1;
581	        i = i + 1;
582	    }
583	    vname[vi] = 0;
584	    fname[0] = 0;
585	    /* Check for .field */
586	    if (s[i] == 46) { /* '.' */
587	        i = i + 1;
588	        int fi = 0;
589	        while (s[i] && s[i] != 32 && s[i] != 9
590	               && fi < MAX_VAR_NAME - 1) {
591	            fname[fi] = s[i];
592	            fi = fi + 1;
593	            i = i + 1;
594	        }
595	        fname[fi] = 0;
596	    }
597	    return i;
598	}
599	
600	/* Runtime error flag — set to 1 on error */
601	int runtime_error;
602	
603	/* Expand variables in tokens. Replaces token_pool/token_starts with
604	 * expanded versions in expand_pool/expand_starts.
605	 * Returns 0 on success, -1 on error (e.g. undefined variable). */
606	int expand_variables() {
607	    expand_count = 0;
608	    expand_pool_used = 0;
609	    runtime_error = 0;
610	    int t = 0;
611	    while (t < token_count) {
612	        char *tok = token_str(t);
613	        int ttype = token_type[t];
614	        expand_starts[expand_count] = expand_pool_used;
615	
616	        if (ttype == TOK_BLOCK) {
617	            /* Blocks are NOT expanded — they are deferred */
618	            int k = 0;
619	            while (tok[k] && expand_pool_used < EXPAND_POOL_SIZE - 1) {
620	                expand_pool[expand_pool_used] = tok[k];
621	                expand_pool_used = expand_pool_used + 1;
622	                k = k + 1;
623	            }
624	        } else if (tok[0] == 36) { /* '$' — entire token is a variable ref */
625	            char vname[MAX_VAR_NAME];
626	            char fname[MAX_VAR_NAME];
627	            parse_var_ref(tok + 1, vname, fname);
628	
629	            int vi = env_get(vname);
630	            if (vi < 0) {
631	                uart_puts("error: undefined variable: ");
632	                uart_puts(vname);
633	                uart_newline();
634	                runtime_error = 1;
635	                return -1;
636	            }
637	
638	            if (fname[0]) {
639	                /* $var.field — record field access */
640	                if (val_type[vi] != VAL_REC) {
641	                    uart_puts("error: not a record: ");
642	                    uart_puts(vname);
643	                    uart_newline();
644	                    runtime_error = 1;
645	                    return -1;
646	                }
647	                int fvi = val_rec_get(vi, fname);
648	                if (fvi < 0) {
649	                    uart_puts("error: no field '");
650	                    uart_puts(fname);
651	                    uart_puts("' in ");
652	                    uart_puts(vname);
653	                    uart_newline();
654	                    runtime_error = 1;
655	                    return -1;
656	                }
657	                /* Format field value as string */
658	                char tmp[MAX_VAR_VAL];
659	                val_to_str(fvi, tmp);
660	                int k = 0;
661	                while (tmp[k] && expand_pool_used < EXPAND_POOL_SIZE - 1) {
662	                    expand_pool[expand_pool_used] = tmp[k];
663	                    expand_pool_used = expand_pool_used + 1;
664	                    k = k + 1;
665	                }
666	            } else {
667	                /* $var — format value as string */
668	                char tmp[MAX_VAR_VAL];
669	                val_to_str(vi, tmp);
670	                int k = 0;
671	                while (tmp[k] && expand_pool_used < EXPAND_POOL_SIZE - 1) {
672	                    expand_pool[expand_pool_used] = tmp[k];
673	                    expand_pool_used = expand_pool_used + 1;
674	                    k = k + 1;
675	                }
676	            }
677	        } else {
678	            /* Plain token — copy as-is */
679	            int k = 0;
680	            while (tok[k] && expand_pool_used < EXPAND_POOL_SIZE - 1) {
681	                expand_pool[expand_pool_used] = tok[k];
682	                expand_pool_used = expand_pool_used + 1;
683	                k = k + 1;
684	            }
685	        }
686	        /* Null-terminate expanded token */
687	        if (expand_pool_used < EXPAND_POOL_SIZE) {
688	            expand_pool[expand_pool_used] = 0;
689	            expand_pool_used = expand_pool_used + 1;
690	        }
691	        expand_count = expand_count + 1;
692	        t = t + 1;
693	    }
694	    return 0;
695	}
