817	int read_line(char *buf, int max) {
818	    int i = 0;
819	    int brace_depth = 0;
820	    while (i < max - 1) {
821	        int ch = uart_getc();
822	        if (ch == 4) { /* Ctrl-D: EOF */
823	            if (i == 0) return -1;
824	            break;
825	        }
826	        if (ch == 10 || ch == 13) { /* newline */
827	            if (brace_depth <= 0) break;
828	            /* Inside braces: treat newline as newline in block */
829	            buf[i] = 10;
830	            i = i + 1;
831	            continue;
832	        }
833	        buf[i] = ch;
834	        i = i + 1;
835	        if (ch == 123) brace_depth = brace_depth + 1; /* '{' */
836	        if (ch == 125) brace_depth = brace_depth - 1; /* '}' */
837	    }
838	    buf[i] = 0;
839	    return i;
840	}
