/* ---- Control flow commands ---- */

int cmd_if() {
    if (expand_count < 3) {
        uart_puts("error: if: expected at least 2 args");
        uart_newline();
        return RET_ERR;
    }
    char cond[MAX_LINE_LEN];
    char body[MAX_LINE_LEN];
    char ebody[MAX_LINE_LEN];
    str_copy(cond, exp_str(1));
    str_copy(body, exp_str(2));
    ebody[0] = 0;
    int has_else = 0;
    if (expand_count >= 5 && str_eq(exp_str(3), "else")) {
        str_copy(ebody, exp_str(4));
        has_else = 1;
    }

    int ret = eval_block(cond);
    if (ret == RET_ERR) return RET_ERR;

    if (val_is_truthy(last_result)) {
        return eval_block(body);
    }
    if (has_else) {
        return eval_block(ebody);
    }
    return RET_OK;
}

int cmd_while() {
    if (expand_count < 3) {
        uart_puts("error: while: expected 2 args");
        uart_newline();
        return RET_ERR;
    }
    char cond[MAX_LINE_LEN];
    char body[MAX_LINE_LEN];
    str_copy(cond, exp_str(1));
    str_copy(body, exp_str(2));

    int max_iter = 10000;
    while (max_iter > 0) {
        max_iter = max_iter - 1;

        int ret = eval_block(cond);
        if (ret == RET_ERR) return RET_ERR;
        if (!val_is_truthy(last_result)) break;

        ret = eval_block(body);
        if (ret == RET_BREAK) break;
        if (ret == RET_ERR) return RET_ERR;
        if (exit_flag) return RET_OK;
        /* RET_CONTINUE: just continue the loop */
    }
    return RET_OK;
}

int cmd_break() {
    return RET_BREAK;
}

int cmd_continue_() {
    return RET_CONTINUE;
}

/* ---- Arithmetic helper: incr ---- */

int cmd_incr() {
    if (expand_count < 2) {
        uart_puts("error: incr: expected variable name");
        uart_newline();
        return RET_ERR;
    }
    char *name = exp_str(1);
    int amount = 1;
    if (expand_count >= 3) {
        amount = str_to_int(exp_str(2));
    }
    int vi = env_get(name);
    if (vi < 0) {
        uart_puts("error: incr: undefined variable: ");
        uart_puts(name);
        uart_newline();
        return RET_ERR;
    }
    if (val_type[vi] != VAL_INT) {
        uart_puts("error: incr: not an integer: ");
        uart_puts(name);
        uart_newline();
        return RET_ERR;
    }
    val_int[vi] = val_int[vi] + amount;
    last_result = vi;
    return RET_OK;
}

/* ---- Command registration ---- */

void register_builtins() {
    cmd_count = 0;
    cmd_register("echo", cmd_echo);
    cmd_register("set", cmd_set);
    cmd_register("exit", cmd_exit);
    cmd_register("exists?", cmd_exists);
    cmd_register("_valtest", cmd_valtest);
    cmd_register("_toktest", cmd_toktest);
}

/* ---- Main ---- */

int main() {
    uart_puts("sws 0.1");
    uart_newline();

    val_reset();
    env_reset();
    exit_flag = 0;
    exit_code = 0;
    register_builtins();

    while (!exit_flag) {
        uart_puts("sws> ");
        int len = read_line(line_buf, MAX_LINE_LEN);
        if (len < 0) break; /* EOF */
        if (len == 0) continue; /* empty line */

        int count = tokenize_line(line_buf);
        if (count < 0) continue; /* syntax error already reported */
        if (count == 0) continue; /* blank or comment-only */

        /* Look up command name in raw tokens */
        char *name = token_str(0);
        int ci = cmd_find(name);

        if (ci < 0) {
            uart_puts("error: unknown command: ");
            uart_puts(name);
            uart_newline();
            continue;
        }

        /* Pre-expansion commands: exists? operates on raw tokens */
        if (str_eq(name, "exists?")) {
            int (*fn)() = cmd_handler[ci];
            fn();
            continue;
        }

        /* Expand variables in tokens */
        if (expand_variables() < 0) continue;

        /* Dispatch to handler */
        int (*fn)() = cmd_handler[ci];
        fn();
    }

    halt();
    return 0;
}

