    exit_flag = 0;
    exit_code = 0;
    register_builtins();

    last_result = val_new_int(0);

    while (!exit_flag) {
        uart_puts("sws> ");
        int len = read_line(line_buf, MAX_LINE_LEN);
        if (len < 0) break; /* EOF */
        if (len == 0) continue; /* empty line */

        eval_line(line_buf);
    }

    halt();
    return 0;
}

