        uart_newline();
        return RET_ERR;
    }

    /* Pre-expansion commands: exists? */
    if (str_eq(name, "exists?")) {
        int (*fn)() = cmd_handler[ci];
        fn();
        return RET_OK;
    }

    if (expand_variables() < 0) return RET_ERR;

    uart_puts("[dispatch]");
    int (*fn)() = cmd_handler[ci];
    return fn();
}

