    if (is_int_str(a) && is_int_str(b)) {
        if (str_to_int(a) > str_to_int(b)) result = 1;
    }
    last_result = val_new_int(result);
    return RET_OK;
}

int cmd_le() {
    if (expand_count < 3) {
        uart_puts("error: le: expected 2 args");
        uart_newline();
        return RET_ERR;
    }
    char *a = exp_str(1);
    char *b = exp_str(2);
    int result = 0;
    if (is_int_str(a) && is_int_str(b)) {
        if (str_to_int(a) <= str_to_int(b)) result = 1;
    }
    last_result = val_new_int(result);
