}

int cmd_or() {
    if (expand_count < 3) {
        uart_puts("error: or: expected 2 args");
        uart_newline();
        return RET_ERR;
    }
    int va = val_from_str(exp_str(1));
    int vb = val_from_str(exp_str(2));
