        while (i < end && (block[i] == 32 || block[i] == 9 || block[i] == 10))
            i = i + 1;
        if (i >= end) break;

        /* Collect one line, respecting brace nesting */
        int li = 0;
        int depth = 0;
        while (i < end && li < MAX_LINE_LEN - 1) {
            if (block[i] == 123) depth = depth + 1;
            if (block[i] == 125) depth = depth - 1;
            if ((block[i] == 10 || block[i] == 59) && depth == 0) {
                i = i + 1;
