int block_push(char *s) {
    int start = block_stack_top;
    int i = 0;
    while (s[i] && block_stack_top < BLOCK_STACK_SIZE - 1) {
        block_stack_pool[block_stack_top] = s[i];
        block_stack_top = block_stack_top + 1;
        i = i + 1;
    }
    block_stack_pool[block_stack_top] = 0;
    block_stack_top = block_stack_top + 1;
    return start;
}

